/**
 * Получить целевое значение из номограммы VISX S4 IR.
 * @param age  возраст пациента (лет)
 * @param val  исходная сфера (D)
 * @returns    скорректированная сфера (D)
 */
export function getNomogramTarget(age: number, val: number): number {
  const ages = Object.keys(NOMOGRAM_DATA).map(Number).sort((a, b) => a - b);
  if (!ages.length) return val;

  let a0 = ages[0];
  let a1 = ages[ages.length - 1];

  if (age <= a0) {
    a1 = a0;
  } else if (age >= a1) {
    a0 = a1;
  } else {
    for (let i = 0; i < ages.length - 1; i++) {
      if (age >= ages[i] && age <= ages[i + 1]) {
        a0 = ages[i];
        a1 = ages[i + 1];
        break;
      }
    }
  }

  const getTarget = (ageKey: number, v: number): number => {
    const map = NOMOGRAM_DATA[String(ageKey)] ?? NOMOGRAM_DATA['40'];
    const nm: Record<number, number> = {};
    Object.keys(map).forEach(k => { nm[parseFloat(k)] = map[k]; });
    const vs = Object.keys(nm).map(Number).sort((a, b) => a - b);
    if (v <= vs[0]) return nm[vs[0]];
    if (v >= vs[vs.length - 1]) return nm[vs[vs.length - 1]];
    for (let i = 0; i < vs.length - 1; i++) {
      if (v >= vs[i] && v <= vs[i + 1]) {
        return interpolate(v, vs[i], nm[vs[i]], vs[i + 1], nm[vs[i + 1]]);
      }
    }
    return v;
  };

  return interpolate(age, a0, getTarget(a0, val), a1, getTarget(a1, val));
}
